const { stagesItems } = window;

(function () {
  if (!stagesNav || !stagesImages || !stagesImagesTemplate || !Array.isArray(stagesItems) || !stagesItems.length) return null;

  stagesItems.forEach(({ title, images }) => {
    const li = document.createElement("li");
    const btn = document.createElement("button");

    btn.innerText = title;
    li.appendChild(btn);

    btn.onclick = function () {
      [...stagesNav.querySelectorAll("li")].forEach(li => {
        li.classList.remove("active");
      });

      stagesImages.innerHTML = "";
      if (!Array.isArray(images) || !images.length) return null;

      this.parentNode.classList.add("active");

      images.forEach(({ image }) => {
        stagesImages.innerHTML += stagesImagesTemplate.innerHTML.replace("{image}", `assets/image/${image}`).replace("{title}", title);
      });
    };

    stagesNav.appendChild(li);
  });

  stagesNav.querySelector("button").onclick();
})();

